(()=>{console.log("This site was generated by Hugo.");document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll('a[href*="index.xml"]').forEach(n=>{n.addEventListener("click",function(o){o.preventDefault();let e=this.href;navigator.clipboard.writeText(e).then(()=>{let t=this.textContent;this.textContent="RSS URL Copied!",setTimeout(()=>{this.textContent=t},2e3)}).catch(t=>{console.error("Failed to copy RSS URL:",t),window.open(e,"_blank")})})})});})();
